114→  // ---------------------------------------------------------------------------
115→  // Full lifecycle: create -> deactivate -> verify removal from active views
116→  // ---------------------------------------------------------------------------
117→
118→  it("deactivated learning disappears from active filtered views", async () => {
119→    const { baseUrl, surreal } = getRuntime();
