123→    // Given: user creates an active learning for coding agents
124→    const createRes = await createLearningViaHttp(baseUrl, user, workspaceId, {
125→      text: "Run linter before every commit.",
126→      learning_type: "instruction",
127→      priority: "medium",
128→      target_agents: ["coding_agent"],
129→    });
