195→    expect(editRes.status).toBe(200);
196→
197→    // Verify edit took effect
198→    const edited = await getLearningById(surreal, learningId);
199→    expect(edited!.text).toBe("Use 2-space indentation for TypeScript, 4-space for Python.");
200→    expect(edited!.priority).toBe("high");
201→    expect(edited!.target_agents).toEqual(["coding_agent", "mcp"]);
202→
203→    // Step 3: user retires the learning
204→    const deactRes = await performLearningAction(
205→      baseUrl, user, workspaceId, learningId,
206→      { action: "deactivate" },
207→    );
208→    expect(deactRes.status).toBe(200);
209→
210→    // Verify the learning is retired
211→    const retired = await getLearningById(surreal, learningId);
212→    expect(retired!.status).toBe("deactivated");
213→    expect(retired!.deactivated_at).toBeTruthy();
214→
215→    // And: it no longer appears in active views
216→    const activeRes = await listLearningsViaHttp(baseUrl, user, workspaceId, { status: "active" });
217→    const activeBody = (await activeRes.json()) as { learnings: Array<{ text: string }> };
218→    expect(activeBody.learnings.some((l) => l.text.includes("indentation"))).toBe(false);
219→  }, 120_000);
220→
221→  // ---------------------------------------------------------------------------
222→  // Multiple learnings lifecycle in same workspace
223→  // ---------------------------------------------------------------------------
224→
225→  it("managing multiple learnings independently in the same workspace", async () => {
226→    const { baseUrl, surreal } = getRuntime();
227→    const user = await createTestUser(baseUrl, `multi-lifecycle-${crypto.randomUUID()}`);
228→    const { workspaceId } = await createTestWorkspace(surreal, "multi-lifecycle");
229→
230→    // Given: user creates three learnings
231→    const res1 = await createLearningViaHttp(baseUrl, user, workspaceId, {
232→      text: "Learning Alpha.", learning_type: "constraint", priority: "high", target_agents: [],
233→    });
234→    const res2 = await createLearningViaHttp(baseUrl, user, workspaceId, {
235→      text: "Learning Beta.", learning_type: "instruction", priority: "medium", target_agents: ["coding_agent"],
236→    });
237→    const res3 = await createLearningViaHttp(baseUrl, user, workspaceId, {
238→      text: "Learning Gamma.", learning_type: "precedent", priority: "low", target_agents: ["pm_agent"],
239→    });
240→    const id1 = ((await res1.json()) as { learningId: string }).learningId;
241→    const id2 = ((await res2.json()) as { learningId: string }).learningId;
242→    const id3 = ((await res3.json()) as { learningId: string }).learningId;
243→
244→    // When: user deactivates Learning Beta
245→    await performLearningAction(baseUrl, user, workspaceId, id2, { action: "deactivate" });
246→
247→    // Then: only Alpha and Gamma remain active
248→    const activeRes = await listLearningsViaHttp(baseUrl, user, workspaceId, { status: "active" });
249→    const activeBody = (await activeRes.json()) as { learnings: Array<{ text: string }> };
250→    expect(activeBody.learnings.length).toBe(2);
251→    const activeTexts = activeBody.learnings.map((l) => l.text);
252→    expect(activeTexts).toContain("Learning Alpha.");
253→    expect(activeTexts).toContain("Learning Gamma.");
254→    expect(activeTexts).not.toContain("Learning Beta.");
255→
256→    // And: deactivated tab shows exactly one
257→    const deactRes = await listLearningsViaHttp(baseUrl, user, workspaceId, { status: "deactivated" });
258→    const deactBody = (await deactRes.json()) as { learnings: Array<{ text: string }> };
259→    expect(deactBody.learnings.length).toBe(1);
260→    expect(deactBody.learnings[0].text).toBe("Learning Beta.");
261→  }, 120_000);
262→
263→  // ---------------------------------------------------------------------------
264→  // Error path: deactivating an already-deactivated learning is rejected
265→  // ---------------------------------------------------------------------------
266→
267→  it("deactivating an already-deactivated learning is rejected", async () => {
268→    const { baseUrl, surreal } = getRuntime();
269→    const user = await createTestUser(baseUrl, `double-deact-${crypto.randomUUID()}`);
270→    const { workspaceId } = await createTestWorkspace(surreal, "double-deact");
271→
272→    // Given: a deactivated learning
273→    const { learningId } = await createTestLearning(surreal, workspaceId, {
274→      text: "Already retired.", learning_type: "instruction", status: "deactivated",
275→    });
276→
277→    // When: user attempts to deactivate again
278→    const response = await performLearningAction(
279→      baseUrl, user, workspaceId, learningId,
280→      { action: "deactivate" },
281→    );
282→
283→    // Then: the action is rejected (invalid state transition)
284→    expect(response.status).toBeGreaterThanOrEqual(400);
285→    expect(response.status).toBeLessThan(500);
286→  }, 120_000);
287→
288→  // ---------------------------------------------------------------------------
289→  // Error path: deactivating a dismissed learning is rejected
290→  // ---------------------------------------------------------------------------
291→
292→  it("deactivating a dismissed learning is rejected", async () => {
293→    const { baseUrl, surreal } = getRuntime();
294→    const user = await createTestUser(baseUrl, `deact-dismissed-${crypto.randomUUID()}`);
295→    const { workspaceId } = await createTestWorkspace(surreal, "deact-dismissed");
296→
297→    // Given: a dismissed learning
298→    const { learningId } = await createTestLearning(surreal, workspaceId, {
299→      text: "Was dismissed.", learning_type: "instruction", status: "dismissed",
300→    });
301→
302→    // When: user attempts to deactivate it
303→    const response = await performLearningAction(
304→      baseUrl, user, workspaceId, learningId,
305→      { action: "deactivate" },
306→    );
307→
308→    // Then: the action is rejected (dismiss and deactivate are different terminal states)
309→    expect(response.status).toBeGreaterThanOrEqual(400);
310→    expect(response.status).toBeLessThan(500);
311→  }, 120_000);
312→});
