  1→/**
  2→ * Agent Learnings Acceptance Test Kit
  3→ *
  4→ * Extends the shared acceptance-test-kit with learning-specific helpers.
  5→ * All helpers use business language -- no technical jargon in function names.
  6→ *
  7→ * Driving ports:
  8→ *   POST   /api/workspaces/:workspaceId/learnings                     (create learning)
  9→ *   GET    /api/workspaces/:workspaceId/learnings                     (list learnings)
 10→ *   POST   /api/workspaces/:workspaceId/learnings/:learningId/actions (status transitions)
 11→ *   SurrealDB direct queries                                         (verification of outcomes)
 12→ */
 13→import { RecordId, type Surreal } from "surrealdb";
 14→import { embedMany } from "ai";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Re-exports from shared kit
 18→// ---------------------------------------------------------------------------
 19→
 20→export {
 21→  setupAcceptanceSuite,
 22→  createTestUser,
 23→  createTestUserWithMcp,
 24→  fetchJson,
 25→  fetchRaw,
 26→  testAI,
 27→  type AcceptanceTestRuntime,
 28→  type TestUser,
 29→  type TestUserWithMcp,
 30→} from "../acceptance-test-kit";
 31→
 32→import {
 33→  setupAcceptanceSuite,
 34→  fetchJson,
 35→  fetchRaw,
 36→  testAI,
 37→  type AcceptanceTestRuntime,
 38→  type TestUser,
 39→} from "../acceptance-test-kit";
 40→
 41→// ---------------------------------------------------------------------------
 42→// Learning Domain Types
 43→// ---------------------------------------------------------------------------
 44→
 45→export type LearningType = "constraint" | "instruction" | "precedent";
 46→
 47→export type LearningStatus =
 48→  | "active"
 49→  | "pending_approval"
 50→  | "dismissed"
 51→  | "superseded"
 52→  | "deactivated";
 53→
 54→export type LearningSource = "human" | "agent";
 55→
 56→export type LearningPriority = "low" | "medium" | "high";
 57→
 58→export type LearningRecord = {
 59→  id: RecordId<"learning">;
 60→  text: string;
 61→  learning_type: LearningType;
 62→  status: LearningStatus;
 63→  source: LearningSource;
 64→  priority: LearningPriority;
 65→  target_agents: string[];
 66→  workspace: RecordId<"workspace">;
 67→  suggested_by?: string;
 68→  pattern_confidence?: number;
 69→  created_by?: RecordId<"identity">;
 70→  created_at: string;
 71→  updated_at?: string;
 72→  approved_by?: RecordId<"identity">;
 73→  approved_at?: string;
 74→  activated_at?: string;
 75→  dismissed_by?: RecordId<"identity">;
 76→  dismissed_at?: string;
 77→  dismissed_reason?: string;
 78→  deactivated_by?: RecordId<"identity">;
 79→  deactivated_at?: string;
 80→  embedding?: number[];
 81→};
 82→
 83→export type CreateLearningInput = {
 84→  text: string;
 85→  learning_type: LearningType;
 86→  priority?: LearningPriority;
 87→  target_agents?: string[];
 88→};
 89→
 90→export type LearningActionInput = {
 91→  action: "approve" | "dismiss" | "deactivate" | "supersede";
 92→  reason?: string;
 93→  new_text?: string;
 94→};
 95→
 96→// ---------------------------------------------------------------------------
 97→// Suite Setup
 98→// ---------------------------------------------------------------------------
 99→
100→/**
101→ * Sets up a learning acceptance test suite with an isolated server + DB.
102→ */
103→export function setupLearningSuite(
104→  suiteName: string,
105→): () => AcceptanceTestRuntime {
106→  return setupAcceptanceSuite(suiteName);
107→}
108→
109→// ---------------------------------------------------------------------------
110→// Domain Helpers -- Business Language Layer
111→// ---------------------------------------------------------------------------
112→
113→/**
114→ * Creates a workspace and identity directly in SurrealDB for learning tests.
115→ * Returns workspace ID and identity ID for use in test scenarios.
116→ */
117→export async function createTestWorkspace(
118→  surreal: Surreal,
119→  suffix: string,
120→): Promise<{ workspaceId: string; identityId: string }> {
121→  const workspaceId = `ws-${crypto.randomUUID()}`;
122→  const identityId = `id-${crypto.randomUUID()}`;
123→  const workspaceRecord = new RecordId("workspace", workspaceId);
124→  const identityRecord = new RecordId("identity", identityId);
125→
126→  await surreal.query(`CREATE $workspace CONTENT $content;`, {
127→    workspace: workspaceRecord,
128→    content: {
129→      name: `Learning Test Workspace ${suffix}`,
130→      status: "active",
131→      onboarding_complete: true,
132→      onboarding_turn_count: 0,
133→      onboarding_summary_pending: false,
134→      onboarding_started_at: new Date(),
135→      created_at: new Date(),
136→    },
137→  });
138→
139→  await surreal.query(`CREATE $identity CONTENT $content;`, {
140→    identity: identityRecord,
141→    content: {
142→      name: `Test User ${suffix}`,
143→      type: "human",
144→      identity_status: "active",
145→      workspace: workspaceRecord,
146→      created_at: new Date(),
147→    },
148→  });
149→
150→  await surreal.query(
151→    `RELATE $identity->member_of->$workspace SET added_at = time::now();`,
152→    { identity: identityRecord, workspace: workspaceRecord },
153→  );
154→
155→  return { workspaceId, identityId };
156→}
157→
158→/**
159→ * Creates a learning record directly in SurrealDB.
160→ * Used as a Given-step to seed learning state for test scenarios.
161→ */
162→export async function createTestLearning(
163→  surreal: Surreal,
164→  workspaceId: string,
165→  overrides: Partial<{
166→    text: string;
167→    learning_type: LearningType;
168→    status: LearningStatus;
169→    source: LearningSource;
170→    priority: LearningPriority;
171→    target_agents: string[];
172→    suggested_by: string;
173→    pattern_confidence: number;
174→    created_by: string;
175→    embedding: number[];
176→  }> = {},
177→): Promise<{ learningId: string; learningRecord: RecordId<"learning"> }> {
178→  const learningId = `learning-${crypto.randomUUID()}`;
179→  const learningRecord = new RecordId("learning", learningId);
180→  const workspaceRecord = new RecordId("workspace", workspaceId);
181→
182→  const content: Record<string, unknown> = {
183→    text: overrides.text ?? "Default test learning text",
184→    learning_type: overrides.learning_type ?? "instruction",
185→    status: overrides.status ?? "active",
186→    source: overrides.source ?? "human",
187→    priority: overrides.priority ?? "medium",
188→    target_agents: overrides.target_agents ?? [],
189→    workspace: workspaceRecord,
190→    created_at: new Date(),
191→  };
192→
193→  if (overrides.suggested_by !== undefined) {
194→    content.suggested_by = overrides.suggested_by;
195→  }
196→  if (overrides.pattern_confidence !== undefined) {
197→    content.pattern_confidence = overrides.pattern_confidence;
198→  }
199→  if (overrides.created_by !== undefined) {
200→    content.created_by = new RecordId("identity", overrides.created_by);
201→  }
202→  if (overrides.embedding !== undefined) {
203→    content.embedding = overrides.embedding;
204→  }
205→  if (overrides.status === "active") {
206→    content.activated_at = new Date();
207→  }
208→
209→  await surreal.query(`CREATE $learning CONTENT $content;`, {
210→    learning: learningRecord,
211→    content,
212→  });
213→
214→  return { learningId, learningRecord };
215→}
216→
217→/**
218→ * Queries active learnings for a workspace, optionally filtered by agent type.
219→ */
220→export async function listActiveLearnings(
221→  surreal: Surreal,
222→  workspaceId: string,
223→  agentType?: string,
224→): Promise<LearningRecord[]> {
225→  const workspaceRecord = new RecordId("workspace", workspaceId);
226→
227→  if (agentType) {
228→    const rows = (await surreal.query(
229→      `SELECT * FROM learning
230→       WHERE workspace = $ws
231→         AND status = "active"
232→         AND (array::len(target_agents) = 0 OR $agentType IN target_agents)
233→       ORDER BY created_at DESC;`,
234→      { ws: workspaceRecord, agentType },
235→    )) as Array<LearningRecord[]>;
236→    return rows[0] ?? [];
237→  }
238→
239→  const rows = (await surreal.query(
240→    `SELECT * FROM learning WHERE workspace = $ws AND status = "active" ORDER BY created_at DESC;`,
241→    { ws: workspaceRecord },
242→  )) as Array<LearningRecord[]>;
243→  return rows[0] ?? [];
244→}
245→
246→/**
247→ * Queries all learnings for a workspace, optionally filtered by status.
248→ */
249→export async function listLearningsByStatus(
250→  surreal: Surreal,
251→  workspaceId: string,
252→  status: LearningStatus,
253→): Promise<LearningRecord[]> {
254→  const workspaceRecord = new RecordId("workspace", workspaceId);
255→  const rows = (await surreal.query(
256→    `SELECT * FROM learning WHERE workspace = $ws AND status = $status ORDER BY created_at DESC;`,
257→    { ws: workspaceRecord, status },
258→  )) as Array<LearningRecord[]>;
259→  return rows[0] ?? [];
260→}
261→
262→/**
263→ * Creates a policy record for collision detection tests.
264→ */
265→export async function createTestPolicy(
266→  surreal: Surreal,
267→  workspaceId: string,
268→  overrides: Partial<{
269→    name: string;
270→    description: string;
271→    rules: Array<Record<string, unknown>>;
272→    embedding: number[];
273→  }> = {},
274→): Promise<{ policyId: string }> {
275→  const policyId = `policy-${crypto.randomUUID()}`;
276→  const policyRecord = new RecordId("policy", policyId);
277→  const workspaceRecord = new RecordId("workspace", workspaceId);
278→
279→  const identityId = `id-${crypto.randomUUID()}`;
280→  const identityRecord = new RecordId("identity", identityId);
281→  await surreal.query(`CREATE $identity CONTENT $content;`, {
282→    identity: identityRecord,
283→    content: {
284→      name: "Policy Creator",
285→      type: "human",
286→      identity_status: "active",
287→      workspace: workspaceRecord,
288→      created_at: new Date(),
289→    },
